Berikut adalah implementasi kelas Python `ApacheLogAnalyzer` untuk audit log akses Apache. Kelas ini dirancang untuk mendeteksi anomali berbasis frekuensi请求 (DDoS/Brute-force) dan pola serangan umum (SQLi, XSS, Path Traversal).

Gunakan skrip ini untuk monitoring defensif. Ini bukan pengganti WAF atau Firewall, melainkan alat analisis forensik awal.

```python
import re
import os
from collections import Counter, defaultdict
from typing import List, Dict, Tuple
from datetime import datetime

class ApacheLogAnalyzer:
    """
    Analisis keamanan log Apache Combined Log Format.
    Fokus: Deteksi IP mencurigakan berdasarkan rate request dan payload attack.
    """

    # Regex Apache Combined Log Format
    LOG_PATTERN = re.compile(
        r'(?P<ip>\d+\.\d+\.\d+\.\d+)\s+'
        r'(?P<ident>\S+)\s+'
        r'(?P<user>\S+)\s+'
        r'\[(?P<timestamp>[^\]]+)\]\s+'
        r'"(?P<method>\S+)\s+(?P<path>\S+)\s+(?P<protocol>[^"]+)"\s+'
        r'(?P<status>\d+)\s+'
        r'(?P<bytes>\S+)\s+'
        r'"(?P<referer>[^"]*)"\s+'
        r'"(?P<agent>[^"]*)"'
    )

    # Pola serangan umum (Defensive Signatures)
    ATTACK_PATTERNS = [
        re.compile(r'(\%27)|(\')|(\-\-)|(\%23)|(#)', re.IGNORECASE),  # SQLi Basic
        re.compile(r'((\%3D)|(=))[^\n]*((\%27)|(\')|(\-\-)|(\%3B)|(;))', re.IGNORECASE), # SQLi Advanced
        re.compile(r'\w*((\%27)|(\'))((\%6F)|o|(\%4F))((\%72)|r|(\%52))', re.IGNORECASE), # SQLi OR
        re.compile(r'((\%3C)|<)((\%2F)|\/)*(script)((\%3E)|>)', re.IGNORECASE), # XSS Script
        re.compile(r'(\.\.\/)|(\.\.\\)', re.IGNORECASE), # LFI/Path Traversal
        re.compile(r'(union)(.*)(select)', re.IGNORECASE), # SQLi Union
    ]

    def __init__(self, log_path: str, threshold_requests: int = 100, window_seconds: int = 60):
        if not os.path.isfile(log_path):
            raise FileNotFoundError(f"Log file tidak ditemukan: {log_path}")

        self.log_path = log_path
        self.threshold_requests = threshold_requests
        self.window_seconds = window_seconds
        self.ip_counts = Counter()
        self.ip_paths = defaultdict(list)
        self.suspicious_ips = {}

    def parse_line(self, line: str) -> Dict:
        match = self.LOG_PATTERN.match(line)
        if not match:
            return {}
        return match.groupdict()

    def detect_attack_pattern(self, path: str) -> bool:
        for pattern in self.ATTACK_PATTERNS:
            if pattern.search(path):
                return True
        return False

    def analyze(self) -> Dict[str, any]:
        """
        Melakukan parsing full log dan mengembalikan laporan keamanan.
        """
        print(f"[+] Memulai audit log: {self.log_path}")

        try:
            with open(self.log_path, 'r', encoding='utf-8', errors='ignore') as f:
                for line in f:
                    data = self.parse_line(line)
                    if not data:
                        continue

                    ip = data['ip']
                    path = data['path']

                    # Hitung frekuensi
                    self.ip_counts[ip] += 1

                    # Cek pola serangan pada URL
                    if self.detect_attack_pattern(path):
                        if ip not in self.suspicious_ips:
                            self.suspicious_ips[ip] = {'reason': [], 'count': 0}
                        if 'Attack Pattern Detected' not in self.suspicious_ips[ip]['reason']:
                            self.suspicious_ips[ip]['reason'].append('Attack Pattern Detected')

                    # Cek status code error (4xx/5xx) untuk brute force detection
                    if data['status'].startswith('4') or data['status'].startswith('5'):
                        if ip not in self.suspicious_ips:
                            self.suspicious_ips[ip] = {'reason': [], 'count': 0}
                        if 'High Error Rate' not in self.suspicious_ips[ip]['reason']:
                            self.suspicious_ips[ip]['reason'].append('High Error Rate')

            # Filter IP berdasarkan threshold request (Potensi DDoS/Scraper)
            for ip, count in self.ip_counts.items():
                if count >= self.threshold_requests:
                    if ip not in self.suspicious_ips:
                        self.suspicious_ips[ip] = {'reason': [], 'count': 0}
                    self.suspicious_ips[ip]['reason'].append(f'High Traffic ({count} requests)')
                    self.suspicious_ips[ip]['count'] = count

        except Exception as e:
            print(f"[-] Error saat parsing: {str(e)}")
            return {}

        return self.generate_report()

    def generate_report(self) -> Dict:
        total_requests = sum(self.ip_counts.values())
        unique_ips = len(self.ip_counts)
        suspicious_count = len(self.suspicious_ips)

        report = {
            'total_requests': total_requests,
            'unique_ips': unique_ips,
            'suspicious_ips_found': suspicious_count,
            'details': self.suspicious_ips
        }

        print(f"[+] Audit Selesai. Total Request: {total_requests}, IP Unik: {unique_ips}")
        print(f"[!] IP Mencurigakan Terdeteksi: {suspicious_count}")

        return report

    def get_block_list(self) -> List[str]:
        """
        Mengembalikan list IP yang direkomendasikan untuk di-blokir di firewall.
        """
        return list(self.suspicious_ips.keys())

# Contoh Penggunaan
if __name__ == "__main__":
    # Ganti dengan path log actual Anda (misal: /var/log/apache2/access.log)
    LOG_FILE = "access.log" 

    try:
        analyzer = ApacheLogAnalyzer(LOG_FILE, threshold_requests=500)
        report = analyzer.analyze()

        if report['suspicious_ips_found'] > 0:
            print("\n[!] REKOMENDASI BLOKIR IP:")
            for ip in analyzer.get_block_list():
                print(f"iptables -A INPUT -s {ip} -j DROP")
        else:
            print("[+] Tidak ada ancaman signifikan terdeteksi berdasarkan parameter saat ini.")

    except FileNotFoundError as e:
        print(f"[-] Critical: {e}")
```

### Catatan Teknis & Mitigasi

1.  **Regex Pattern**: Pattern di atas mencakup standar Combined Log Format. Jika server Anda menggunakan custom format, sesuaikan `LOG_PATTERN`.
2.  **Threshold**: Nilai `threshold_requests` harus disesuaikan dengan trafik normal server. Setting terlalu rendah akan menyebabkan *false positive*.
3.  **Kinerja**: Untuk log berukuran GB, pertimbangkan memproses file secara bergantian (`chunking`) atau menggunakan tool seperti `GoAccess` untuk visualisasi real-time.
4.  **Action**: Output script ini menghasilkan rekomendasi rule `iptables`. Jangan langsung eksekusi tanpa verifikasi manual. Integrasikan dengan Fail2Ban untuk automasi yang lebih aman.
5.  **Keamanan**: Script ini berjalan secara pasif. Pastikan server Anda sudah dilindungi oleh WAF (Web Application Firewall) seperti ModSecurity atau Cloudflare untuk mitigasi aktif.

Jika membutuhkan integrasi dengan panel tertentu (Pterodactyl/WHM), beri tahu spesifikasi lingkungan server Anda.
